// Daily Formation, one pre-written Catholic formation entry for every journey day.
//
// Shown on the Today rhythm as a short daily teaching. The entry is chosen by
// the user's current journey day (see getDailyFormation), never randomly and
// never repeated. If the journey day has no entry yet, Day 1 is shown.
//
// STATUS: First review batch authored for Days 1-30. The remaining days
// (31-365) fall back to Day 1 until the full set is written and approved.
//
// Content rules followed throughout:
//   - Worship belongs to God alone; Mary and the saints intercede and point to
//     Christ.
//   - Scripture, Tradition, and private revelation are kept distinct.
//   - No em dashes.

export type DailyFormation = {
  day: number;
  title: string;
  category: string;
  summary: string;
  formationText: string;
  reflection: string;
  // Optional internal references for theological review and future expansion.
  // Not displayed on the Today card yet.
  scriptureReferences?: string[];
  catechismReferences?: string[];
};

