export function getDailyFormation(day: number): DailyFormation {
  const entry = dailyFormation.find((e) => e.day === day);
  if (entry) return entry;
  const fallback = dailyFormation.find((e) => e.day === 1);
  return fallback ?? dailyFormation[0];
}
